import microservices_pb2 as pb2
import microservices_pb2_grpc as pb2_grpc


class MicroservicesClient:
    def __init__(self, host: str = "localhost", port: int = 50051):
        self.channel = grpc.insecure_channel(f"{host}:{port}")
        self.auth_stub = pb2_grpc.AuthServiceStub(self.channel)
        self.data_stub = pb2_grpc.DataServiceStub(self.channel)

    def login(self, username: str, password: str):
        return self.auth_stub.Login(pb2.LoginRequest(username=username, password=password))

    def logout(self, token: str):
        return self.auth_stub.Logout(pb2.LogoutRequest(token=token))

    def refresh_token(self, token: str):
        return self.auth_stub.RefreshToken(pb2.RefreshTokenRequest(token=token))

    def get_user_data(self, user_id: str, token: str):
        return self.data_stub.GetUserData(pb2.GetUserDataRequest(user_id=user_id, token=token))

    def list_users(self, token: str):
        return self.data_stub.ListUsers(pb2.ListUsersRequest(token=token))


